patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index 56bd79f41460..72f0cd70a85a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -3346,6 +3346,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
       Value *Arg = II->getArgOperand(0);
       Value *Vect;

+
       if (Value *NewOp =
               simplifyReductionOperand(Arg, /*CanReorderLanes=*/true)) {
         replaceUse(II->getOperandUse(0), NewOp);
@@ -3519,6 +3520,16 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
   //  * The select condition is not a vector, or the intrinsic does not
   //    perform cross-lane operations.
   switch (IID) {
+  case Intrinsic::fabs: {
+    // fabs(fneg(x)) -> fabs(x)
+    Value *Arg = II->getArgOperand(0);
+    Value *X;
+    if (match(Arg, m_FNeg(m_Value(X)))) {
+      replaceUse(II->getOperandUse(0), X);
+      return II;
+    }
+    [[fallthrough]];
+  }
   case Intrinsic::ctlz:
   case Intrinsic::cttz:
   case Intrinsic::ctpop:
@@ -3547,6 +3558,7 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
   return visitCallBase(*II);
 }

+
 // Fence instruction simplification
 Instruction *InstCombinerImpl::visitFenceInst(FenceInst &FI) {
   auto *NFI = dyn_cast<FenceInst>(FI.getNextNonDebugInstruction());

